from flask import Flask, request, redirect, url_for, session
import requests

app = Flask(__name__)
app.secret_key = 'your secret key'  # replace with your own secret key

@app.route('/')
def index():
    if 'access_token' in session:
        return "You are already logged in"
    else:
        return redirect(url_for('login'))

@app.route('/login')
def login():
    client_id = 'your client id'  # replace with your own client id
    redirect_uri = url_for('callback', _external=True)
    authorization_endpoint = "https://authorization-server.com/auth"
    
    return redirect(f"{authorization_endpoint}?response_type=code&client_id={client_id}&redirect_uri={redirect_uri}")

@app.route('/callback')
def callback():
    client_secret = 'your client secret'  # replace with your own client secret
    code = request.args.get('code')
    
    token_endpoint = "https://authorization-server.com/token"
    data = {
        'grant_type': 'authorization_code',
        'client_id': 'your client id',  # replace with your own client id
        'client_secret': client_secret,
        'redirect_uri': url_for('callback', _external=True),
        'code': code
    }
    
    response = requests.post(token_endpoint, data=data)
    access_token = response.json().get('access_token')
    
    if access_token:
        session['access_token'] = access_token
        
    return redirect(url_for('index'))